INSERT INTO public.movie_picks (id, season_id, user_id, tmdb_id, title, poster_url, year, overview, watch_order, revealed, created_at) VALUES
  ('9e75256f-c58e-4375-a3cc-8be1ab63d598', 'fd2d0dc5-bce4-4139-a51d-3f3390658322', 'c530de58-6e21-4746-b567-fd8ff7ff7e4e', 587792, 'Palm Springs', 'https://image.tmdb.org/t/p/w200/gnAfqiV7yO3Jq9IntTmwkcaICqc.jpg', '2020', 'When carefree Nyles and reluctant maid of honor Sarah have a chance encounter at a Palm Springs wedding, things get complicated when they find themselves unable to escape the venue, themselves, or each other.', 1, true, '2026-03-04 20:58:33.81549+00'),
  ('6cf163c6-0725-4234-9df9-421fccc5c532', '4925baa2-7075-44d4-85ab-489b54bbd2d9', '8eeaae0d-ccbd-4fc5-8467-f87396b1f92c', 1398, 'Stalker', 'https://image.tmdb.org/t/p/w200/1qhOyf5C4s9ZdvY8d5JDx9DFMeT.jpg', '1979', 'Near a gray and unnamed city is the Zone, a place guarded by barbed wire and soldiers, and where the normal laws of physics are victim to frequent anomalies. A stalker guides two men into the Zone, specifically to an area in which deep-seated desires are granted.', 0, false, '2026-03-08 20:19:29.069516+00'),
  ('93c4cd94-8f23-4bd3-b1aa-79e321dd13c7', '63b16319-723b-4be2-ac81-a5015ac3f31f', '8eeaae0d-ccbd-4fc5-8467-f87396b1f92c', NULL, 'Harry Potter and the Chamber of Secrets', 'https://books.google.com/books/content?id=5iTebBW-w7QC&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api', '2015', 'Harry Potter''s summer has included the worst birthday ever, doomy warnings from a house-elf called Dobby, and rescue from the Dursleys by his friend Ron Weasley in a magical flying car! Back at Hogwarts School of Witchcraft and Wizardry for his second year, Harry hears strange whispers echo through empty corridors - and then the attacks start. Students are found as', NULL, false, '2026-03-20 15:36:01.273977+00'),
  ('8ad911e9-b6db-4686-8874-9daa6f2e25e9', '15d5e389-4ee0-4972-9dc4-e0b42bdeae7a', '8eeaae0d-ccbd-4fc5-8467-f87396b1f92c', 19542, 'The Red Shoes', 'https://image.tmdb.org/t/p/w200/vPvpBWFWDvEXuQBkoYgA6A89GVp.jpg', '1948', NULL, 1, true, '2026-03-04 20:45:09.390801+00'),
  ('6328f91a-ed94-49e3-b8c0-941af7c29edf', 'a9b57039-43a0-4e81-bbb7-3c348aa561cf', '42542128-e74c-462d-a196-932574e5ecb4', 5825, 'National Lampoon''s Christmas Vacation', 'https://image.tmdb.org/t/p/w200/oat42hUw8XzKYUmfy0YLAxYd484.jpg', '1989', NULL, 2, true, '2026-03-04 20:51:20.492718+00'),
  ('48aaad3e-e80a-4b38-88bd-e6e3ef32f4b2', 'fd2d0dc5-bce4-4139-a51d-3f3390658322', '8eeaae0d-ccbd-4fc5-8467-f87396b1f92c', 284, 'The Apartment', 'https://image.tmdb.org/t/p/w200/hhSRt1KKfRT0yEhEtRW3qp31JFU.jpg', '1960', 'Bud Baxter is a minor clerk in a huge New York insurance company, until he discovers a quick way to climb the corporate ladder. He lends out his apartment to the executives as a place to take their mistresses. Although he often has to deal with the aftermath of their visits, one night he''s left with a major problem to solve.', 5, false, '2026-03-04 20:58:33.81549+00'),
  ('81f2d3b9-c9f0-41f4-b694-adf156667e41', 'a9b57039-43a0-4e81-bbb7-3c348aa561cf', 'c530de58-6e21-4746-b567-fd8ff7ff7e4e', 20334, 'The Shop Around the Corner', 'https://image.tmdb.org/t/p/w200/dZ1aEzGYRiqJwPfjS6VL7wUkHmF.jpg', '1940', NULL, 4, true, '2026-03-04 20:51:20.492718+00'),
  ('d0aaa244-780d-4010-ac1a-08d26aa98c3a', '214ec89e-b640-4545-b0f7-4ed9158451a2', '8eeaae0d-ccbd-4fc5-8467-f87396b1f92c', NULL, 'American War', 'https://books.google.com/books/content?id=OyQYDQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api', '2017', 'NATIONAL BESTSELLER • A second American Civil War, a devastating plague, and one family caught deep in the middle—this gripping debut novel asks what might happen if America were to turn its most devastating policies and deadly weapons upon itself. From the author of What Strange Paradise "Powerful ... as haunting a postapocalyptic universe as Cormac McCarthy [created] in The Road." —The New York Times Sarat Chestnut, born in Louisiana, is only six when the Second American Civil War breaks out i', 0, false, '2026-03-20 15:48:06.103695+00'),
  ('ed1066d4-a425-4960-929a-a02a33b45c42', 'fd2d0dc5-bce4-4139-a51d-3f3390658322', 'c8efb932-ad9e-41fb-b610-77db59797ebf', 419430, 'Get Out', 'https://image.tmdb.org/t/p/w200/tFXcEccSQMf3lfhfXKSU9iRBpa3.jpg', '2017', 'Chris and his girlfriend Rose go upstate to visit her parents for the weekend. At first, Chris reads the family''s overly accommodating behavior as nervous attempts to deal with their daughter''s interracial relationship, but as the weekend progresses, a series of increasingly disturbing discoveries lead him to a truth that he never could have imagined.', 0, true, '2026-03-04 20:58:33.81549+00'),
  ('65316aa7-b445-4884-884f-b18caa826f6b', '15d5e389-4ee0-4972-9dc4-e0b42bdeae7a', '42542128-e74c-462d-a196-932574e5ecb4', 1239655, 'Friendship', 'https://image.tmdb.org/t/p/w200/eikAu9gPJTQQmwFwa1zX5Hfz96P.jpg', '2024', NULL, 2, true, '2026-03-04 20:45:09.390801+00'),
  ('338d8cf1-414a-42d4-a54d-df59fd1fb505', 'a9b57039-43a0-4e81-bbb7-3c348aa561cf', '8eeaae0d-ccbd-4fc5-8467-f87396b1f92c', 25842, 'A Christmas Carol', 'https://image.tmdb.org/t/p/w200/cvr7x3CjBMsHv2GptR0tcFddMSa.jpg', '1938', NULL, 3, true, '2026-03-04 20:51:20.492718+00'),
  ('0a587d9f-b47f-4f1f-9b61-946d00a45c99', '15d5e389-4ee0-4972-9dc4-e0b42bdeae7a', 'c530de58-6e21-4746-b567-fd8ff7ff7e4e', 422, '8 1/2', 'https://image.tmdb.org/t/p/w200/nqOsvzEamX7AyNwSx48OOV2iidE.jpg', '1963', NULL, 6, true, '2026-03-04 20:45:09.390801+00'),
  ('41027d43-d2a8-490b-986e-cc55201f1425', 'fd2d0dc5-bce4-4139-a51d-3f3390658322', '42542128-e74c-462d-a196-932574e5ecb4', 994108, 'All of Us Strangers', 'https://image.tmdb.org/t/p/w200/aviJMFZSnnCAsCVyJGaPNx4Ef3i.jpg', '2023', 'One night in his near-empty tower block in contemporary London, Adam has a chance encounter with a mysterious neighbor Harry, which punctures the rhythm of his everyday life.', 2, true, '2026-03-04 20:58:33.81549+00'),
  ('9a78532a-4e97-4f03-b8b5-eebd8a6eae4b', 'fd2d0dc5-bce4-4139-a51d-3f3390658322', '28fb7843-c6f3-4ed4-9e58-3c4e4299542e', 440472, 'The Upside', 'https://image.tmdb.org/t/p/w500/hPZ2caow1PCND6qnerfgn6RTXdm.jpg', '2017', 'Phillip is a wealthy quadriplegic who needs a caretaker to help him with his day-to-day routine in his New York penthouse. He decides to hire Dell, a struggling parolee who''s trying to reconnect with his ex and his young son. Despite coming from two different worlds, an unlikely friendship starts to blossom.', 4, true, '2026-03-04 20:58:33.81549+00'),
  ('fae415a6-5111-41d7-b946-a1520c63f40e', 'a9b57039-43a0-4e81-bbb7-3c348aa561cf', 'f867e22e-137e-4754-9eb0-4b25e91ebae8', 927, 'Gremlins', 'https://image.tmdb.org/t/p/w200/6m0F7fsXjQvUbCZrPWcJNrjvIui.jpg', '1984', NULL, 0, true, '2026-03-04 20:51:20.492718+00'),
  ('67395741-b1d8-4c9b-958f-c552636dbadd', 'fd2d0dc5-bce4-4139-a51d-3f3390658322', 'f867e22e-137e-4754-9eb0-4b25e91ebae8', 72105, 'Ted', 'https://image.tmdb.org/t/p/w200/1QVZXQQHCEIj8lyUhdBYd2qOYtq.jpg', '2012', 'John Bennett, a man whose childhood wish of bringing his teddy bear to life came true, now must decide between keeping the relationship with the bear or his girlfriend, Lori.', 3, true, '2026-03-04 20:58:33.81549+00'),
  ('e1ff9726-0160-402a-adbf-7fba6b9d5ab9', '15d5e389-4ee0-4972-9dc4-e0b42bdeae7a', 'f867e22e-137e-4754-9eb0-4b25e91ebae8', 2469, 'Tie Me Up! Tie Me Down!', 'https://image.tmdb.org/t/p/w200/4eNyqA543ixNCME8pcADgP9wb1i.jpg', '1989', NULL, 5, true, '2026-03-04 20:45:09.390801+00'),
