  ('1294e0cb-8513-4a18-beed-f6f95086f547', '15d5e389-4ee0-4972-9dc4-e0b42bdeae7a', '08b16c97-8e4b-42ed-98a6-cfe8a417c908', 968, 'Dog Day Afternoon', 'https://image.tmdb.org/t/p/w200/mavrhr0ig2aCRR8d48yaxtD5aMQ.jpg', '1975', NULL, 4, true, '2026-03-04 20:45:09.390801+00'),
  ('9da23244-017b-40d9-a725-2d06d46b981d', 'fd2d0dc5-bce4-4139-a51d-3f3390658322', '08b16c97-8e4b-42ed-98a6-cfe8a417c908', 1019939, 'Hundreds of Beavers', 'https://image.tmdb.org/t/p/w200/qgXS9HrYaYDnILeXebatCbtX9IP.jpg', '2022', 'In the 19th century, a drunken applejack salesman must go from zero to hero and become North America''s greatest fur trapper by defeating hundreds of beavers.', 6, true, '2026-03-04 21:49:09.846617+00'),
  ('302ec5c9-9bd3-44b3-a602-3294984bef5c', 'a9b57039-43a0-4e81-bbb7-3c348aa561cf', 'c8efb932-ad9e-41fb-b610-77db59797ebf', 5825, 'National Lampoon''s Christmas Vacation', 'https://image.tmdb.org/t/p/w200/oat42hUw8XzKYUmfy0YLAxYd484.jpg', '1989', NULL, 2, true, '2026-03-04 20:51:20.492718+00'),
  ('63c57551-d11a-40dc-8477-0d3b62cf4c2b', '15d5e389-4ee0-4972-9dc4-e0b42bdeae7a', 'c8efb932-ad9e-41fb-b610-77db59797ebf', 496243, 'Parasite', 'https://image.tmdb.org/t/p/w200/7IiTTgloJzvGI1TAYymCfbfl3vT.jpg', '2019', NULL, 3, true, '2026-03-04 20:45:09.390801+00'),
  ('946d0fcd-e477-49ca-bbf3-3963ba374353', 'a93ef2e0-bb9e-4898-a2b6-ef32c032c402', 'f867e22e-137e-4754-9eb0-4b25e91ebae8', 51876, 'Limitless', 'https://image.tmdb.org/t/p/w200/kCokPP4WCQRrrAuZ7FcpIyHr8b2.jpg', '2011', 'The life of an unsuccessful writer is transformed by a top-secret ''smart drug'' that allows him to use 100% of his brain and become a perfect version of himself. His enhanced abilities soon attract shadowy forces that threaten his new life.', 2, false, '2026-04-05 00:50:43.807884+00'),
  ('8b6c613e-7bce-4acb-ab99-e8dd0dd77c64', 'a93ef2e0-bb9e-4898-a2b6-ef32c032c402', '28fb7843-c6f3-4ed4-9e58-3c4e4299542e', 1887, 'Marie Antoinette', 'https://image.tmdb.org/t/p/w200/cybXGmv8Rjd5Os8Xml6YxMBQ0Zt.jpg', '2006', 'A retelling of the story of France''s iconic but ill-fated queen, Marie Antoinette - from her betrothal and marriage to Louis XVI at fifteen to her reign as queen at nineteen and ultimately the fall of Versailles.', 3, false, '2026-04-04 16:00:51.953513+00'),
  ('f571af8d-f21e-4bbe-8d03-97a2c53cf14b', 'a93ef2e0-bb9e-4898-a2b6-ef32c032c402', '8eeaae0d-ccbd-4fc5-8467-f87396b1f92c', 9008, 'The Insider', 'https://image.tmdb.org/t/p/w200/jJCyIBPfvk41uETq6K6u4upyGO8.jpg', '1999', 'A research chemist comes under personal and professional attack when he decides to appear in a 60 Minutes exposé on Big Tobacco.', 0, false, '2026-04-02 03:22:58.432937+00'),
  ('2ad6fa89-27c3-45ae-b0ba-9714c2681691', 'a93ef2e0-bb9e-4898-a2b6-ef32c032c402', '42542128-e74c-462d-a196-932574e5ecb4', 671, 'Harry Potter and the Philosopher''s Stone', 'https://image.tmdb.org/t/p/w200/wuMc08IPKEatf9rnMNXvIDxqP4W.jpg', '2001', 'Harry Potter has lived under the stairs at his aunt and uncle''s house his whole life. But on his 11th birthday, he learns he''s a powerful wizard—with a place waiting for him at the Hogwarts School of Witchcraft and Wizardry. As he learns to harness his newfound powers with the help of the school''s kindly headmaster, Harry uncovers the truth about his parents'' deaths—and about the villain who''s to blame.', 1, false, '2026-04-03 02:16:52.944522+00'),
  ('2619a946-2175-48ad-a8dc-5a4dbb76e401', 'a93ef2e0-bb9e-4898-a2b6-ef32c032c402', '08b16c97-8e4b-42ed-98a6-cfe8a417c908', 1456349, 'It Was Just an Accident', 'https://image.tmdb.org/t/p/w200/eNYGj2DG3n8OrVPTfYunpPW9uas.jpg', '2025', 'An unassuming mechanic is reminded of his time in an Iranian prison when he encounters a man he suspects to be his sadistic jailhouse captor.', 4, false, '2026-04-03 18:10:48.449741+00'),
  ('3b840787-8976-4f27-bc90-bbef4718c861', 'a93ef2e0-bb9e-4898-a2b6-ef32c032c402', 'c530de58-6e21-4746-b567-fd8ff7ff7e4e', 10112, 'The Aristocats', 'https://image.tmdb.org/t/p/w200/1BVOSmQUhphMgnTxnXyfQ9tL1Sc.jpg', '1970', 'When Madame Adelaide Bonfamille leaves her fortune to Duchess and her children—Bonfamille''s beloved family of cats—the butler plots to steal the money and kidnaps the legatees, leaving them out on a country road. All seems lost until the wily Thomas O''Malley Cat and his jazz-playing alley cats come to the aristocats'' rescue.', 5, false, '2026-04-02 05:22:23.346633+00'),
  ('ad68685f-2763-445c-9ff1-1ac4cf7d272d', 'a93ef2e0-bb9e-4898-a2b6-ef32c032c402', 'c8efb932-ad9e-41fb-b610-77db59797ebf', 85, 'Raiders of the Lost Ark', 'https://image.tmdb.org/t/p/w200/ceG9VzoRAVGwivFU403Wc3AHRys.jpg', '1981', 'When Dr. Indiana Jones – the tweed-suited professor who just happens to be a celebrated archaeologist – is hired by the government to locate the legendary Ark of the Covenant, he finds himself up against the entire Nazi regime.', 6, false, '2026-04-02 03:26:34.235545+00')
